import { Logger } from '@nestjs/common';

import {
	TABLE_NAME_GITHUB_CONTRIBUTORS,
	TABLE_NAME_GITHUB_INSTALLATIONS,
} from '@constants/db.constant';

import type { Knex } from 'knex';

const logger = new Logger('20260416000000_create_github_contributors_table.ts');

export async function up(knex: Knex): Promise<void> {
	logger.log('Creating github_contributors table');

	await knex.transaction(async (trx) => {
		const tableExists = await trx.schema.hasTable(TABLE_NAME_GITHUB_CONTRIBUTORS);

		if (!tableExists) {
			await trx.schema.createTable(TABLE_NAME_GITHUB_CONTRIBUTORS, (table) => {
				table.uuid('_id').primary().notNullable();
				table
					.uuid('installation_id')
					.notNullable()
					.references('_id')
					.inTable(TABLE_NAME_GITHUB_INSTALLATIONS);
				table.bigInteger('github_user_id').notNullable();
				table.string('github_login', 255).notNullable();
				table.string('github_name', 255).nullable();
				table.string('github_email', 255).nullable();
				table.uuid('platform_user_id').nullable();
				table
					.timestamp('created_at', { useTz: true })
					.defaultTo(trx.fn.now())
					.notNullable();
				table
					.timestamp('updated_at', { useTz: true })
					.defaultTo(trx.fn.now())
					.notNullable();

				table.unique(['installation_id', 'github_user_id']);
				table.index(['installation_id']);
				table.index(['github_login']);
			});

			logger.log('Successfully created github_contributors table');
		} else {
			logger.log('github_contributors table already exists, skipping');
		}
	});
}

export async function down(knex: Knex): Promise<void> {
	logger.log('Dropping github_contributors table');

	await knex.transaction(async (trx) => {
		await trx.schema.dropTableIfExists(TABLE_NAME_GITHUB_CONTRIBUTORS);
	});
}

